SELECT
    ,
    u.name AS user_name
FROM rental_reservation r
LEFT JOIN `user` u ON r.user_id = u.id AND u.deleted = 0
WHERE r.deleted = 0

    AND r.room_id = #{request.roomId}


    AND r.status = #{request.status}


    AND r.start_datetime >= #{request.from}


    AND r.end_datetime <= #{request.to}


    AND u.name LIKE CONCAT('%', #{request.userName}, '%')

ORDER BY r.start_datetime DESC

SELECT
    ,
    u.name AS user_name
FROM rental_reservation r
LEFT JOIN "user" u ON r.user_id = u.id AND u.deleted = 0
WHERE r.deleted = 0

    AND r.room_id = #{request.roomId}


    AND r.status = #{request.status}


    AND r.start_datetime >= #{request.from}


    AND r.end_datetime <= #{request.to}


    AND u.name LIKE '%' || #{request.userName} || '%'

ORDER BY r.start_datetime DESC

SELECT COALESCE(SUM(r.total_price), 0)
FROM rental_reservation r
LEFT JOIN `user` u ON r.user_id = u.id AND u.deleted = 0
WHERE r.deleted = 0

    AND r.room_id = #{request.roomId}


    AND r.status = #{request.status}


    AND r.start_datetime >= #{request.from}


    AND r.end_datetime <= #{request.to}


    AND u.name LIKE CONCAT('%', #{request.userName}, '%')

