UPDATE rental_reservation
SET status = #{cancelledByUserStatus},
    updated_at = #{now},
    updated_by = #{userId}
WHERE id = #{id}
  AND user_id = #{userId}
  AND deleted = 0
  AND status IN (#{requestedStatus}, #{confirmedStatus})
